{
 "entities": [
  {
   "id": "character:keeper",
   "name": "Maren Voss",
   "concept": "Keeper of the Stilt Light, third of her family to hold the bargain.",
   "details": {
    "appearance": "weathered hands, oilskin coat",
    "manner": "economical with words"
   }
  },
  {
   "id": "character:cartographer",
   "name": "Elias Wren",
   "concept": "A coastal cartographer hired to chart the shoals, curious to a fault.",
   "details": {
    "manner": "asks one question too many, means every kindness"
   }
  },
  {
   "id": "character:sleeper",
   "name": "The Sleeper",
   "concept": "The vast thing below the shoals that the light keeps dreaming.",
   "details": {
    "appearance": "never fully seen; a shadow the size of weather"
   }
  },
  {
   "id": "location:lighthouse",
   "name": "The Stilt Light",
   "concept": "A lighthouse on iron stilts over the shoals, lamp fed by whale-oil and habit."
  }
 ],
 "dilemmas": [
  {
   "id": "dilemma:bargain",
   "question": "Does Maren keep the bargain or break it?",
   "why_it_matters": "The light is the only thing keeping the sleeper down. Keeping it costs Maren the sea and Elias; breaking it buys her life back at the coast's expense.",
   "role": "hard",
   "residue_weight": "heavy",
   "ending_salience": "high",
   "answers": [
    {
     "id": "answer:bargain-kept",
     "text": "She keeps the light burning, whatever it costs her."
    },
    {
     "id": "answer:bargain-broken",
     "text": "She lets the light die and takes her life back."
    }
   ],
   "anchored_to": [
    "character:keeper",
    "character:sleeper",
    "location:lighthouse"
   ]
  },
  {
   "id": "dilemma:truth",
   "question": "Does Maren tell Elias what the light holds?",
   "why_it_matters": "Telling him makes Elias an ally inside the bargain's danger; hiding it keeps him safe and builds a lie that will stand at her shoulder when the choice comes.",
   "role": "soft",
   "residue_weight": "light",
   "ending_salience": "low",
   "answers": [
    {
     "id": "answer:truth-told",
     "text": "She tells him what sleeps under the shoals."
    },
    {
     "id": "answer:truth-hidden",
     "text": "She blames the instruments and burns the page."
    }
   ],
   "anchored_to": [
    "character:keeper",
    "character:cartographer"
   ]
  }
 ]
}
